import { GoogleGenAI } from "@google/genai";
import { Message } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are a mindful AI assistant representing the philosophy of the author 'Ra Tha'. 
Ra Tha explains Buddhist concepts (Dhamma) in modern, simple terms for the current generation (IT, AI age).
Key concepts:
- "Religion is not something to do, but something to know."
- "Boomerang Karma": Actions are energies that return to the source.
- "Zero Concept": Understanding the voidness of all phenomena to escape suffering.
- "The Light Code": The natural law behind existence.

Instructions:
1. Speak in a helpful, calm, and insightful tone.
2. Use Myanmar language (Burmese) primarily, as the audience is Myanmar-speaking. You can use English for technical terms or "Ra Tha" specific terms (like Boomerang Karma).
3. Be concise and practical.
4. If asked about the author, explain that Ra Tha translates 2500-year-old wisdom for the modern mind.
5. Do not talk about politics or controversial social issues. Focus on mindful understanding of the mind and nature.
`;

export const getDhammaInsight = async (history: Message[], prompt: string): Promise<string> => {
  try {
    const chat = ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    const response = await chat;
    return response.text || "စိတ်မကောင်းပါဘူး။ ကျွန်တော် မသိလိုက်ပါဘူး။ နောက်တစ်ကြိမ် မေးကြည့်ပေးပါ။";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "ယခုအချိန်တွင် ဆက်သွယ်မှု အခက်အခဲရှိနေပါသည်။ ခဏကြာမှ ပြန်လည်ကြိုးစားပေးပါ။";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Tab, Book, Article, Message } from './types';
import { BOOKS, ARTICLES, QUOTES } from './constants';
import { getDhammaInsight } from './services/geminiService';

// --- Components ---

const Header: React.FC = () => (
