          }`}
        >
          <svg className={`w-6 h-6 ${activeTab === tab.id ? 'stroke-2' : 'stroke-1.5'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
            {tab.icon}
          </svg>
          <span className="text-[10px]">{tab.label}</span>
          {activeTab === tab.id && <div className="w-1 h-1 bg-black rounded-full mt-0.5" />}
        </button>
      ))}
