};

const Modal: React.FC<{ isOpen: boolean; onClose: () => void; children: React.ReactNode }> = ({ isOpen, onClose, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 bg-black/40 backdrop-blur-[2px] flex items-end sm:items-center justify-center p-0 sm:p-4" onClick={onClose}>
      <div 
        className="bg-white w-full max-w-lg rounded-t-3xl sm:rounded-3xl h-[90vh] sm:h-auto sm:max-h-[85vh] overflow-y-auto p-6 relative animate-in slide-in-from-bottom duration-300" 
        onClick={e => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-4 right-4 w-10 h-10 bg-neutral-100 rounded-full flex items-center justify-center text-xl font-light hover:bg-neutral-200 transition-colors">×</button>
        <div className="pt-4">{children}</div>
        <div className="h-12" />
      </div>
    </div>
  );
};

// --- Main App ---

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.HOME);
  const [loading, setLoading] = useState(true);
  const [quoteIndex, setQuoteIndex] = useState(0);
  const [selectedBook, setSelectedBook] = useState<Book | null>(null);
  const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
  const [chatHistory, setChatHistory] = useState<Message[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setQuoteIndex(prev => (prev + 1) % QUOTES.length);
    }, 6000);
    return () => clearInterval(interval);
  }, []);

  const handleTabChange = (tab: Tab) => {
    setActiveTab(tab);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSendMessage = async () => {
    if (!chatInput.trim()) return;
    const userMsg: Message = { role: 'user', text: chatInput };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput('');
    setIsAiLoading(true);

    try {
      const insight = await getDhammaInsight(chatHistory, chatInput);
      setChatHistory(prev => [...prev, { role: 'model', text: insight }]);
    } catch (err) {
      setChatHistory(prev => [...prev, { role: 'model', text: "တောင်းပန်ပါတယ်၊ အမှားတစ်ခုခု ဖြစ်သွားပါတယ်။" }]);
    } finally {
      setIsAiLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="fixed inset-0 z-[100] bg-white flex flex-col items-center justify-center animate-pulse">
        <h1 className="text-4xl font-bold tracking-[0.2em] text-neutral-800 mb-2">RA THA</h1>
        <p className="text-neutral-400 italic text-sm">Light Code for Modern Mind</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#fcfcfc] pb-24">
      <Header />

      <main className="pt-20 px-5 max-w-2xl mx-auto overflow-x-hidden">
        {activeTab === Tab.HOME && (
          <div className="animate-in fade-in duration-500">
            {/* Hero */}
            <section className="py-6">
              <div className="rounded-[2.5rem] bg-neutral-900 text-white p-10 relative overflow-hidden mb-10 shadow-2xl shadow-neutral-300">
                <div className="relative z-10">
                  <h2 className="text-3xl font-bold mb-4 leading-tight">စိတ်အထုံးများ ပြေလျော့စေပြီး လောကမှ နိုးထခြင်း</h2>
                  <p className="text-neutral-400 text-sm leading-relaxed mb-6 font-light">
                    လောကဓမ္မနှင့် သဘာဝတရားကို ခေတ်သစ်အမြင်ဖြင့် ရှင်းလင်းတင်ပြထားသော စာရေးဆရာ Ra Tha ၏ စာအုပ်များ
                  </p>
                  <button 
                    onClick={() => handleTabChange(Tab.BOOKS)}
                    className="bg-white text-black px-8 py-3 rounded-full text-xs font-bold uppercase tracking-widest hover:bg-neutral-200 transition-all active:scale-95"
                  >
                    စာအုပ်များကြည့်မည်
                  </button>
                </div>
                <div className="absolute -right-20 -bottom-20 w-64 h-64 bg-neutral-800 rounded-full blur-[80px] opacity-40"></div>
