                </div>
                <div className="h-48 rounded-[2rem] bg-neutral-100 overflow-hidden shadow-inner">
                    <img src="https://images.unsplash.com/photo-1518199266791-5375a83190b7?auto=format&fit=crop&q=80&w=1000" className="w-full h-full object-cover grayscale opacity-80" alt="Nature" />
                </div>
            </div>
          </div>
