                      ? 'bg-neutral-900 text-white rounded-tr-none' 
                      : 'bg-neutral-50 text-neutral-800 rounded-tl-none border border-neutral-100'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))}
                {isAiResponding && (
                  <div className="flex justify-start">
                    <div className="bg-neutral-50 rounded-[1.75rem] rounded-tl-none px-8 py-5 flex gap-2 border border-neutral-100 shadow-sm">
                       <div className="w-2 h-2 bg-neutral-300 rounded-full animate-bounce" />
                       <div className="w-2 h-2 bg-neutral-300 rounded-full animate-bounce [animation-delay:0.2s]" />
                       <div className="w-2 h-2 bg-neutral-300 rounded-full animate-bounce [animation-delay:0.4s]" />
                    </div>
                  </div>
                )}
                <div ref={chatEndRef} />
              </div>

              <div className="flex gap-3 pt-4 border-t border-neutral-50">
                <input 
                  type="text" 
                  value={chatInput}
                  onChange={(e) => setChatInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  placeholder="သိလိုရာ မေးမြန်းပါ..."
                  disabled={isAiResponding}
                  className="flex-1 bg-neutral-50 border-none rounded-2xl px-6 py-4 text-sm focus:ring-2 focus:ring-neutral-200 outline-none transition-all placeholder:text-neutral-300"
                />
                <button 
                  onClick={handleSendMessage}
                  disabled={isAiResponding || !chatInput.trim()}
                  className="bg-neutral-900 text-white w-14 h-14 rounded-2xl flex items-center justify-center disabled:opacity-30 active:scale-95 transition-all shadow-xl shadow-neutral-200 flex-shrink-0"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 12h14M12 5l7 7-7 7" /></svg>
                </button>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Book Summary Modal */}
      <Modal isOpen={!!selectedBook} onClose={() => setSelectedBook(null)}>
        {selectedBook && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200">
            <div className="space-y-2">
                <h2 className="text-4xl font-bold text-neutral-800 leading-tight">{selectedBook.title}</h2>
                <p className="text-sm text-neutral-400 italic tracking-wide font-light uppercase">{selectedBook.subtitle}</p>
            </div>

            <p className="text-neutral-700 leading-relaxed text-xl font-light">
              {selectedBook.summary}
            </p>

            <div className="space-y-6">
                <h3 className="font-bold text-xs tracking-[0.2em] uppercase text-neutral-300">Key Insights:</h3>
                <ul className="grid grid-cols-1 gap-4">
                  {selectedBook.topics.map((topic, i) => (
                    <li key={i} className="flex items-center gap-4 p-5 bg-neutral-50 rounded-2xl border border-neutral-100 hover:border-neutral-300 transition-colors">
                      <div className="w-8 h-8 bg-neutral-900 text-white rounded-xl flex items-center justify-center text-[10px] font-bold flex-shrink-0 shadow-lg">
                        {i + 1}
                      </div>
                      <span className="text-neutral-700 text-sm font-medium">{topic}</span>
                    </li>
                  ))}
                </ul>
            </div>

            <div className="pt-6">
               <button className="w-full bg-neutral-900 text-white py-6 rounded-3xl font-bold text-sm tracking-widest uppercase hover:bg-black transition-all shadow-2xl active:scale-[0.98]">
                 Pre-order Copy
               </button>
            </div>
          </div>
        )}
      </Modal>

      {/* Article Detail Modal */}
      <Modal isOpen={!!selectedArticle} onClose={() => setSelectedArticle(null)}>
        {selectedArticle && (
          <div className="space-y-10 animate-in fade-in zoom-in-95 duration-200">
            <h2 className="text-4xl font-bold text-neutral-800 leading-tight border-b border-neutral-100 pb-8">{selectedArticle.title}</h2>
            <div className="space-y-10 text-neutral-700 leading-relaxed text-xl font-light">
              {selectedArticle.content.map((p, i) => (
                <p key={i} className="first-letter:text-5xl first-letter:font-bold first-letter:mr-4 first-letter:float-left first-letter:text-neutral-900 first-letter:mt-1">
                  {p}
                </p>
              ))}
            </div>
            <div className="p-10 bg-neutral-900 rounded-[2.5rem] text-center italic text-white/40 text-sm font-light leading-relaxed relative overflow-hidden">
              <div className="relative z-10">"သဘောတရားကို နားလည်ခြင်းဖြင့်သာ စိတ်သည် လွတ်မြောက်နိုင်ပါသည်။"</div>
              <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent opacity-10"></div>
            </div>
          </div>
        )}
      </Modal>

      <BottomNav activeTab={activeTab} onTabChange={switchTab} />
    </div>
  );
};

