                    ? 'text-2xl sm:text-3xl mm-leading' 
                    : 'text-xl sm:text-2xl md:text-3xl lg:text-[2.1rem] lg:whitespace-nowrap lg:tracking-tight'
                  }`}
                >
                    {TRANSLATIONS.hero.title[language]}
                </h2>
                <p className="text-neutral-400 text-sm leading-relaxed font-light max-w-2xl">
                  {TRANSLATIONS.hero.subtitle[language]}
