  const toggleLanguage = () => {
    setLanguage(prev => (prev === 'mm' ? 'en' : 'mm'));
  };

  if (isInitialLoading) {
    return (
      <div className="fixed inset-0 z-[100] bg-white flex flex-col items-center justify-center">
        <div className="relative flex flex-col items-center">
            <h1 className="text-4xl font-bold tracking-[0.3em] text-neutral-800 animate-pulse">RA THA</h1>
            <p className="text-neutral-400 italic text-sm mt-3 font-light">Light Code for Modern Mind</p>
        </div>
      </div>
    );
