                        onClick={() => switchTab(Tab.BOOKS)}
                        className="bg-white text-black px-8 py-3 rounded-2xl text-xs font-bold uppercase tracking-widest hover:bg-neutral-200 transition-all active:scale-95 shadow-lg"
