            <section className="bg-white rounded-[2.5rem] p-10 shadow-sm border border-neutral-100 flex flex-col items-center text-center">
                <div className="text-neutral-200 mb-6">
                    <svg className="w-8 h-8 mx-auto" fill="currentColor" viewBox="0 0 24 24"><path d="M14.017 21v-7.391c0-5.704 3.731-9.57 8.983-10.609l.995 2.151c-2.432.917-3.995 3.638-3.995 5.849h4v10h-9.983zm-14.017 0v-7.391c0-5.704 3.748-9.57 9-10.609l.996 2.151c-2.433.917-3.996 3.638-3.996 5.849h3.983v10h-9.983z" /></svg>
                </div>
                <p className="text-neutral-700 leading-relaxed text-lg sm:text-xl font-light min-h-[6rem] italic transition-opacity duration-500 mm-leading">
                  {QUOTES[quoteIndex][language]}
                </p>
                <div className="mt-8 flex justify-center space-x-2">
                  {QUOTES.map((_, i) => (
                    <div 
                      key={i} 
                      className={`h-1.5 rounded-full transition-all duration-500 ${quoteIndex === i ? 'w-8 bg-neutral-900' : 'w-2 bg-neutral-100'}`} 
                    />
                  ))}
                </div>
            </section>

            <div className="flex justify-center">
                 <div onClick={() => switchTab(Tab.CHAT)} className="group bg-neutral-50 p-8 rounded-[2.5rem] border border-neutral-100 flex flex-col items-center text-center cursor-pointer hover:bg-neutral-100 transition-all w-full sm:max-w-md">
                    <div className="w-14 h-14 bg-white rounded-[1.25rem] shadow-sm flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                       <svg className="w-7 h-7 text-black" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                    </div>
                    <span className="text-base font-bold">{TRANSLATIONS.nav.chat[language]}</span>
                    <span className="text-xs text-neutral-400 mt-2">{language === 'mm' ? 'စာအုပ်အနှစ်သာရများအား မေးမြန်းပါ' : 'Ask about book essences'}</span>
                 </div>
            </div>
          </div>
        )}

        {/* ABOUT TAB */}
        {activeTab === Tab.ABOUT && (
          <div className="py-6 animate-fade-in space-y-8">
            <h3 className="text-2xl sm:text-3xl font-bold text-neutral-800 tracking-tight mm-leading">{TRANSLATIONS.about.title[language]}</h3>
            <div className="bg-white rounded-[2.5rem] p-10 shadow-sm border border-neutral-100 leading-relaxed text-neutral-600">
                <p className="mb-8">
                    {TRANSLATIONS.about.p1[language]}
                </p>
                <div className="relative p-8 mb-8 border-l-4 border-black bg-neutral-50 rounded-r-[1.5rem] italic text-neutral-500 font-light text-lg mm-leading">
                    {TRANSLATIONS.about.quote[language]}
                    <div className="absolute top-4 right-6 text-neutral-200 opacity-20"><svg className="w-20 h-20" fill="currentColor" viewBox="0 0 24 24"><path d="M14.017 21v-7.391c0-5.704 3.731-9.57 8.983-10.609l.995 2.151c-2.432.917-3.995 3.638-3.995 5.849h4v10h-9.983zm-14.017 0v-7.391c0-5.704 3.748-9.57 9-10.609l.996 2.151c-2.433.917-3.996 3.638-3.996 5.849h3.983v10h-9.983z" /></svg></div>
                </div>
                <p>
                    {TRANSLATIONS.about.p2[language]}
                </p>
            </div>
          </div>
        )}

        {/* BOOKS TAB */}
        {activeTab === Tab.BOOKS && (
          <div className="py-6 animate-fade-in space-y-8">
            <h3 className="text-2xl sm:text-3xl font-bold text-neutral-800 tracking-tight mm-leading">{TRANSLATIONS.nav.books[language]}</h3>

            <GeminiGemCard language={language} />

            <div className="grid grid-cols-1 gap-8">
              {BOOKS.map(book => (
                <div 
                  key={book.id} 
                  className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-neutral-100 flex flex-col sm:flex-row gap-8 hover:shadow-xl hover:border-neutral-200 transition-all cursor-pointer group"
                  onClick={() => setSelectedBook(book)}
                >
                  <div className="w-full sm:w-36 h-56 bg-neutral-900 rounded-[1.5rem] flex-shrink-0 flex flex-col items-center justify-center text-white text-[10px] text-center p-6 font-bold relative overflow-hidden shadow-xl">
                    <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-white/10 to-transparent"></div>
                    <span className="relative z-10 text-xs uppercase tracking-widest opacity-60 mb-2">Ra Tha</span>
                    <span className="relative z-10 text-sm leading-relaxed mm-leading">{book.title[language]}</span>
                    <div className="absolute -right-6 -bottom-6 w-16 h-16 bg-white/5 rounded-full blur-2xl"></div>
                  </div>
                  <div className="flex flex-col justify-center py-2 flex-1">
                    <div className="flex items-center gap-3 mb-3">
                        <span className="text-[10px] bg-neutral-100 px-3 py-1 rounded-full text-neutral-500 font-bold uppercase tracking-widest">{book.tag[language]}</span>
                    </div>
                    <h4 className="font-bold text-lg sm:text-xl mb-2 text-neutral-800 leading-tight group-hover:translate-x-1 transition-transform mm-leading">{book.title[language]}</h4>
                    <p className="text-sm text-neutral-400 mb-6 font-light">{book.subtitle[language]}</p>
                    <button className="w-fit text-xs font-bold text-black border-b-2 border-black pb-1 hover:pb-2 transition-all flex items-center gap-2">
                      {language === 'mm' ? 'အနှစ်ချုပ်ဖတ်ရှုရန်' : 'View Summary'}
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 8l4 4m0 0l-4 4m4-4H3" /></svg>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* BLOG TAB */}
        {activeTab === Tab.BLOG && (
          <div className="py-6 animate-fade-in space-y-8">
            <h3 className="text-2xl sm:text-3xl font-bold text-neutral-800 tracking-tight mm-leading">{TRANSLATIONS.nav.blog[language]}</h3>
            <div className="space-y-6">
              {ARTICLES.map(article => (
                <div 
                  key={article.id} 
                  onClick={() => setSelectedArticle(article)}
                  className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-neutral-100 cursor-pointer hover:shadow-xl hover:bg-neutral-50 transition-all flex flex-col sm:flex-row sm:items-center justify-between group"
                >
                  <div className="flex-1 pr-6">
                    <h4 className="font-bold text-lg sm:text-xl mb-3 text-neutral-800 group-hover:text-neutral-600 transition-colors leading-relaxed mm-leading">{article.title[language]}</h4>
                    <p className="text-sm text-neutral-400 line-clamp-2 leading-relaxed font-light">
                      {article.preview[language]}
                    </p>
                  </div>
                  <div className="mt-6 sm:mt-0 w-12 h-12 bg-neutral-100 rounded-full flex items-center justify-center text-neutral-400 group-hover:bg-neutral-900 group-hover:text-white transition-all shadow-inner">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* CHAT TAB (Official Gem Gateway) */}
        {activeTab === Tab.CHAT && (
          <div className="py-12 animate-fade-in flex flex-col items-center justify-center min-h-[60vh] text-center space-y-8">
            <div className="space-y-4">
              <h3 className="text-2xl sm:text-3xl font-bold text-neutral-800 tracking-tight mm-leading">{TRANSLATIONS.chat.title[language]}</h3>
              <p className="text-neutral-500 max-w-sm mx-auto font-light leading-relaxed">
                {TRANSLATIONS.chat.subtitle[language]}
              </p>
            </div>

            <GeminiGemCard language={language} hideMargin={true} />

            <button 
              onClick={() => switchTab(Tab.HOME)}
              className="text-xs font-bold text-neutral-400 uppercase tracking-widest hover:text-neutral-800 transition-colors flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7" /></svg>
              {TRANSLATIONS.chat.back[language]}
            </button>
          </div>
        )}
      </main>

      {/* Book Summary Modal */}
      <Modal isOpen={!!selectedBook} onClose={() => setSelectedBook(null)}>
        {selectedBook && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200">
            <div className="space-y-2">
                <h2 className="text-2xl sm:text-4xl font-bold text-neutral-800 leading-tight mm-leading">{selectedBook.title[language]}</h2>
                <p className="text-sm text-neutral-400 italic tracking-wide font-light uppercase">{selectedBook.subtitle[language]}</p>
            </div>

            <p className="text-neutral-700 leading-relaxed text-lg sm:text-xl font-light">
              {selectedBook.summary[language]}
            </p>

            <div className="space-y-6">
                <h3 className="font-bold text-xs tracking-[0.2em] uppercase text-neutral-300">Key Insights:</h3>
                <ul className="grid grid-cols-1 gap-4">
                  {selectedBook.topics.map((topic, i) => (
                    <li key={i} className="flex items-center gap-4 p-5 bg-neutral-50 rounded-2xl border border-neutral-100 hover:border-neutral-300 transition-colors">
                      <div className="w-8 h-8 bg-neutral-900 text-white rounded-xl flex items-center justify-center text-[10px] font-bold flex-shrink-0 shadow-lg">
                        {i + 1}
                      </div>
                      <span className="text-neutral-700 text-sm font-medium mm-leading">{topic[language]}</span>
                    </li>
                  ))}
                </ul>
            </div>

            <div className="pt-6 flex flex-col gap-4">
               <button className="w-full bg-neutral-900 text-white py-6 rounded-3xl font-bold text-sm tracking-widest uppercase hover:bg-black transition-all shadow-2xl active:scale-[0.98]">
                 {language === 'mm' ? 'စာအုပ်မှာယူမည်' : 'Order Hard Copy'}
               </button>
               <button 
                onClick={() => window.open(GEMINI_GEM_URL, '_blank')}
                className="w-full bg-indigo-50 text-indigo-700 py-6 rounded-3xl font-bold text-sm tracking-widest uppercase hover:bg-indigo-100 transition-all border border-indigo-100 flex items-center justify-center gap-2"
               >
                 <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L15.09 8.26L22 9.27L17 14.14L18.18 21.02L12 17.77L5.82 21.02L7 14.14L2 9.27L8.91 8.26L12 2Z" /></svg>
                 {language === 'mm' ? 'AI ဖြင့် အသေးစိတ်လေ့လာမည်' : 'Deep Dive with Expert AI'}
               </button>
            </div>
          </div>
        )}
      </Modal>

      {/* Article Detail Modal */}
      <Modal isOpen={!!selectedArticle} onClose={() => setSelectedArticle(null)}>
        {selectedArticle && (
          <div className="space-y-10 animate-in fade-in zoom-in-95 duration-200">
            <h2 className="text-2xl sm:text-4xl font-bold text-neutral-800 leading-tight border-b border-neutral-100 pb-8 mm-leading">{selectedArticle.title[language]}</h2>
            <div className="space-y-10 text-neutral-700 leading-relaxed text-lg sm:text-xl font-light">
              {selectedArticle.content.map((p, i) => (
                <p key={i} className="first-letter:text-5xl first-letter:font-bold first-letter:mr-4 first-letter:float-left first-letter:text-neutral-900 first-letter:mt-1 mm-leading">
                  {p[language]}
                </p>
              ))}
            </div>
            <div className="p-10 bg-neutral-900 rounded-[2.5rem] text-center italic text-white/40 text-sm font-light leading-relaxed relative overflow-hidden">
              <div className="relative z-10 mm-leading">
                {language === 'mm' 
                  ? '"သဘောတရားကို နားလည်ခြင်းဖြင့်သာ စိတ်သည် လွတ်မြောက်နိုင်ပါသည်။"' 
                  : '"Only through understanding the principle can the mind be free."'
                }
              </div>
              <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent opacity-10"></div>
            </div>
          </div>
        )}
      </Modal>

      <BottomNav activeTab={activeTab} onTabChange={switchTab} language={language} />
    </div>
  );
};

export default App;
